// Products.js
import React from "react";
import "../index.css";

const products = [
  {
    id: 1,
    name: "Apple AirPods Pro 2nd gen",
    description: "Apple AirPods Pro (2nd Gen) with MagSafe case",
    price: 399.99,
    rating: 4.5,
    image: "https://store.storeimages.cdn-apple.com/4982/as-images.apple.com/is/MQD83?...",
  },
  {
    id: 2,
    name: "Canon EOS R5",
    description: "The Canon EOS R5 is a game-changing mirrorless camera",
    price: 3899.99,
    rating: 4.5,
    image: "https://www.canon.ca/dam/products/BUSINESS-UNIT/ITCG/Cameras/EOS-Cameras/Mirrorless/EOS-R5/Canon_EOS-R5_Side_580x580.png",
  },
  {
    id: 3,
    name: "PlayStation 5",
    description: "The PlayStation 5 takes gaming to the next level",
    price: 499.99,
    rating: 4.5,
    image: "https://pngpix.com/images/hd/ps5-console-design-png-tyu77-b85oqvhgnkdd752d.jpg",
  },
  {
    id: 4,
    name: "Samsung Galaxy S23",
    description: "The Samsung Galaxy S23 offers an amazing smartphone experience",
    price: 799.99,
    rating: 4.5,
    image: "https://www.pngall.com/wp-content/uploads/13/Galaxy-S23-PNG-Images.png",
  },
  {
    id: 5,
    name: "Sony WH-1000XM4",
    description: "Industry-leading noise canceling headphones",
    price: 349.99,
    rating: 4.7,
    image: "https://d1ncau8tqf99kp.cloudfront.net/converted/106682_original_local_1200x1050_v3_converted.webp",
  },
  {
    id: 6,
    name: "Dell XPS 13",
    description: "Compact, powerful, and stylish ultrabook",
    price: 1199.99,
    rating: 4.6,
    image: "https://i.dell.com/sites/imagecontent/products/PublishingImages/hero/22617-home-laptop-xps-13-9350-504x350.png",
  },
  {
    id: 7,
    name: "Apple Watch Series 8",
    description: "Advanced health features and fitness tracking",
    price: 399.99,
    rating: 4.4,
    image: "https://img-prd-pim.poorvika.com/product/Apple-watch-series-8-gps-45mm-mp6n3hn-a-Front-Right-View.png",
  },
  {
    id: 8,
    name: "GoPro Hero 11",
    description: "Capture stunning 5.3K video and 27MP photos",
    price: 499.99,
    rating: 4.6,
    image: "https://images.frandroid.com/wp-content/uploads/2022/09/gopro-hero-11-black-frandroid-2022.png",
  },
  {
    id: 9,
    name: "MacBook Pro 16-inch",
    description: "Powerful performance with M2 Pro chip",
    price: 2499.99,
    rating: 4.8,
    image: "https://support.apple.com/library/APPLE/APPLECARE_ALLGEOS/SP858/mbp16-gray.png",
  },
  {
    id: 10,
    name: "Bose SoundLink Revolve+",
    description: "Deep, loud and immersive sound speaker",
    price: 299.99,
    rating: 4.5,
    image: "https://m.media-amazon.com/images/I/61zK3yP2rfL._SX522_.jpg",
  },
  {
    id: 11,
    name: "iPad Pro 12.9",
    description: "The ultimate iPad experience with M2 chip",
    price: 1099.99,
    rating: 4.7,
    image: "https://store.storeimages.cdn-apple.com/4982/as-images.apple.com/is/ipad-pro-12-11-select-202210",
  },
  {
    id: 12,
    name: "Fitbit Charge 6",
    description: "Fitness tracker with heart rate monitoring",
    price: 179.99,
    rating: 4.3,
    image: "https://m.media-amazon.com/images/I/61nC5AZ0yUL._SX522_.jpg",
  },
  {
    id: 13,
    name: "Xbox Series X",
    description: "The fastest, most powerful Xbox ever",
    price: 499.99,
    rating: 4.6,
    image: "https://m.media-amazon.com/images/I/61JGKhqxHxL._SX522_.jpg",
  },
  {
    id: 14,
    name: "DJI Mini 3 Pro",
    description: "Lightweight and portable drone with 4K camera",
    price: 899.99,
    rating: 4.7,
    image: "https://m.media-amazon.com/images/I/71zxbLMYd7L._SX522_.jpg",
  },
  {
    id: 15,
    name: "Nintendo Switch OLED",
    description: "Gaming console with vibrant OLED display",
    price: 349.99,
    rating: 4.6,
    image: "https://m.media-amazon.com/images/I/61-PblYntsL._SX522_.jpg",
  },
];

const Products = () => {
  return (
    <div className="products-container">
      <h2 className="section-title">All products</h2>
      <div className="products-grid">
        {products.map((product) => (
          <div className="product-card" key={product.id}>
            <div className="product-img">
              <img src={product.image} alt={product.name} />
            </div>
            <h3 className="product-name">{product.name}</h3>
            <p className="product-desc">{product.description}</p>
            <div className="product-rating">
              {Array.from({ length: 5 }, (_, i) => (
                <span
                  key={i}
                  className={i < Math.floor(product.rating) ? "star filled" : "star"}
                >
                  ★
                </span>
              ))}
              <span className="rating-value">{product.rating}</span>
            </div>
            <div className="product-footer">
              <span className="product-price">${product.price.toFixed(2)}</span>
              <button className="buy-btn">Buy now</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Products;
